export function getPostBySlug(slug: string): Post | undefined {
  return posts.find((post) => post.slug === slug);
}

export function getPostsByCategory(categorySlug: string): Post[] {
  const category = categories.find((c) => c.slug === categorySlug);
  if (!category) return [];
  return posts.filter((post) => post.category === category.name && post.status === "published");
}

export function getRelatedPosts(currentSlug: string, limit: number = 3): Post[] {
  const current = getPostBySlug(currentSlug);
  if (!current) return [];
  return posts
    .filter((p) => p.slug !== currentSlug && p.status === "published")
    .filter((p) => p.category === current.category || p.tags.some((t) => current.tags.includes(t)))
    .slice(0, limit);
}

export function getAllSlugs(): string[] {
  return posts.filter((p) => p.status === "published").map((p) => p.slug);
}

export function getFeaturedPosts(): Post[] {
  return posts.filter((p) => p.featured && p.status === "published");
}

export function getTrendingPosts(): Post[] {
  return posts.filter((p) => p.trending && p.status === "published").sort((a, b) => (b.views || 0) - (a.views || 0));
}

export function getRecentPosts(limit: number = 6): Post[] {
  return posts
    .filter((p) => p.status === "published")
    .sort((a, b) => new Date(b.publishedAt).getTime() - new Date(a.publishedAt).getTime())
    .slice(0, limit);
}

export function getPopularPosts(limit: number = 6): Post[] {
  return posts
    .filter((p) => p.status === "published")
    .sort((a, b) => (b.views || 0) - (a.views || 0))
    .slice(0, limit);
}

export function searchPosts(query: string): Post[] {
  const lower = query.toLowerCase();
  return posts.filter(
    (p) =>
      p.status === "published" &&
      (p.title.toLowerCase().includes(lower) ||
        p.excerpt.toLowerCase().includes(lower) ||
        p.tags.some((t) => t.toLowerCase().includes(lower)) ||
        p.category.toLowerCase().includes(lower))
  );
}


